do case case &EmpCod.IsEmpty() or &FilCod.IsEmpty() &UserMessage = criaUserMessageError('Empresa não identificada','') return
case &NFeCliCod.IsEmpty() &UserMessage = criaUserMessageError('Informe um cliente','') return
case &NFeLctCod.IsEmpty() &UserMessage = criaUserMessageError('Informe um tipo de lançamento','') return
case &NFeProCod.IsEmpty() &UserMessage = criaUserMessageError('Informe um produto','') return
case &NFePesLiq <= 0 &UserMessage = criaUserMessageError('Peso líquido deve ser maior que zero','') return
case &NFePesBrt <= 0 &UserMessage = criaUserMessageError('Peso bruto deve ser maior que zero','') return
case &NfeProQtd <= 0 &UserMessage = criaUserMessageError('Quantidade deve ser maior que zero','') return endcase
// Inicializa variáveis padrão &NfeDtaDsp = ServerDate() &NfeDtaEms = ServerDate() &NfeHorEms = ServerTime() &NfeFin = NotaFinalidade.EmissaoNormal &NfeEntSai = Status_EntradaSaida.Saida &ModCod = '55' &NfeIndPres = '9' &NfeProTer = Nota_ProPriaTerceira.PROPRIA &NfeDtaFat = ServerDate() &NfeIsNFAe = false &NfeCliEntIs = false &NfeTraTipPes = TipoPessoa.FISICA
do 'buscaCliente' do 'buscaTipoLancamento' do 'buscaProduto'
// Prepara AuxNfeCliIns para a chamada if &NfeCliTipPes = TipoPessoa.JURIDICA &AuxNfeCliIns = &NfeCliIns if &NfeCliIns.IsEmpty() &AuxNfeCliIns = 'ISENTO' endif Else &AuxNfeCliIns = &NfeCadPro endif
// Chama a gravação da capa GravaNotaFiscalModelo55_Capa(&EmpCod, &FilCod, &NfeDtaEms, &NfeDtaDsp, &NfeHorEms, &NfeNum, &NfeSer, &NfeFin, &NfeLctCod, &NfeCliEml, &NfeCliCod, &NfeCliRaz, &NfeCliTipPes, &NfeCliCpf, &NfeCliCnpj, &NfeClifon, &AuxNfeCliIns, &NfeCliSuf, &NfeCliEnd, &NfeCliEndNro, &NfeCliBai, &NfeCliCep, &NfeCliCidCod, &NfeCliCpl, &NfeDadAdi, &NfeCod, &NfeTraPlaCod, &NfeTraPlaUF, &NfeTraRntc, &NfeMotNom, &NfeTraCod, &NfeTraRaz, &NfeTraTipPes, &NfeTraEnd, &NfeTraEndNro, &NfeTraBai, &NfeTraEml, &NfeTraCidCod, &NfeTraCnpj, &NfeTraInsEst, &NfeTraCpf, &NfeTraCep, &NfeTipFrt, &NfePesLiq, &NfePesBrt, &NfeQtdVol, &NfeEspVol, &NfeMarVol, &NfeNroVol, &NfeChvRef, &NfeProTer, &NfeCidExp, &ModCod, &NfeChv, &NfeDtaFat, &NfeIndPres, &NfeXped, &NfeIsNFAe, &IntermediadorPesCnpj, &MrkSellUser)
if &NfeCod = 0 &UserMessage = criaUserMessageError('Erro ao gravar a capa da nota fiscal','') return endif
// Grava o item da nota fiscal do 'gravaItemNota' if not &UserMessage.isSucess return endif
// Atualiza os totais da nota AtualizaTotaisNFe(&EmpCod, &FilCod, &NfeCod, 0)
// Observação automática da nota ObsAutomaticaNFe(&EmpCod, &FilCod, &NfeCod)
&UserMessage = criaUserMessageSucesso('Nota fiscal gravada com sucesso','')
Sub 'buscaCliente' for each order EmpCod, PesCod where EmpCod = &EmpCod where PesCod = &NFeCliCod
if PesSts = Status_AtivoInativo.INATIVO &UserMessage = criaUserMessageError('Cliente com Status INATIVO!','') return endif
if PesBlqNfe = Status_SimNao.Sim &UserMessage = criaUserMessageError('Cliente com emissão fiscal bloqueada!','') return endif
&NfeCliEnd = PesEntLog &NfeCliEndNro = PesEntNro &NfeCliBai = PesEntBai &NfeCliCep = PesEntCep &NfeCliCpl = PesEntCpl &NfeCliCidCod = PesEntCidCod &NfeCliCnpj = PesCnpj &NfeCliIns = PesInsEst &NfeCadPro = PesCadPro &NfeCliSuf = PesSuf
if PesRazNf.IsEmpty() or PesRazNf.IsNull() &NfeCliRaz = PesRaz Else &NfeCliRaz = PesRazNf endif
&NfeClifon = PesPrmFon &NfeCliTipPes = PesTip &NfeCliCpf = PesCpf
for each order EmpCod, PesCod, PesEmlCod where PesEmlFat = true
&NfeCliEml = PesEml
Exit endfor
Exit when none &UserMessage = criaUserMessageError('Cliente não encontrado!','') return endfor EndSub
Sub 'buscaTipoLancamento' for each order EmpCod, LctCod where EmpCod = &EmpCod where LctCod = &NFeLctCod Exit when none &UserMessage = criaUserMessageError('Tipo de lançamento não encontrado!','') return endfor EndSub
Sub 'buscaProduto' // Busca informações do produto &ProCatCod = 1
for each order EmpCod, ProCod, ProGraCod where EmpCod = &EmpCod where ProCod = &NFeProCod where ProGraCod = &NfeProGraCod
// Valida se o produto está ativo if ProSts = Status_AtivoInativo.INATIVO &UserMessage = criaUserMessageError('Produto com Status INATIVO!','') return endif
// Informações básicas do produto &ProPesLiq = ProPesLiqPrd &ProCatCod = ProCatCod &ProOriTriCod = ProOriTriCod
// Nome do produto if ProNomNF.IsEmpty() or ProNomNF.IsNull() &NfeProNom = ProNomGra Else &NfeProNom = ProNomNF if ProGraCod > 1 &NfeProNom += ' | ' + trim(ProGraNom) endif endif
// Unidade de medida &NfeEmbUnd = ProEmbUnd if not ProUndTrib.IsEmpty() and not ProUndTrib.IsNull() &NfeEmbUndTrib = ProUndTrib Else &NfeEmbUndTrib = ProEmbUndTrib endif
// Dados adicionais &NfeProDadAdi = ProDetNfe
// NCM e CEST &NfeNcmCod = NcmCod &NfeNcmCest = trim(Str(ProNcmCest))
// Código de barras &NfeProBar = '' &NfeProBarTrib = '' &Varchar = Substr(trim(ProGraBar), 1, 3) if &Varchar <> '333' and not &Varchar.IsEmpty() ValidaEAN13(ProCod, ProGraBar, &NfeProBar, &AuxMensagem) if &AuxMensagem.IsEmpty() if not ProBarTrib.IsEmpty() and not ProBarTrib.IsNull() &NfeProBarTrib = ProBarTrib Else &NfeProBarTrib = &NfeProBar endif endif endif
// Rastreabilidade &NfeProRctPen = ProStsRag
// ICMS Retenção &ProBasIcmsRet = ProBasIcmsRet &ProVlrIcmsRet = ProVlrIcmsRet &ProTaxIcmsRet = ProTaxIcmsRet
// Dados ANP (se obrigatório) if ProObrAnp = Status_simNao.Sim &NfeProCodAnp = ProCodAnp &NfeProDscAnp = ProDscAnp &NfeProPerGlp = ProPerGlp &NfeProPerGni = ProPerGni &NfeProPerGnn = ProPerGnn &NfeProVlrPar = ProVlrPar endif
// Específicos MT For each order EmpCod, FilCod where EmpCod = &EmpCod where FilCod = &FilCod &FilCidUfeCod = FilCidUfeCod Exit endfor
if &FilCidUfeCod = 'MT' &ProIsFabov = ProIsFabov &ProIsIagro = ProIsIagro &ProIsGadoFethab = ProIsGadoFethab &ProIsSojaFethab = ProIsSojaFethab &ProIncFabov = ProIncFabov &ProIncIagro = ProIncIagro &ProIncGadoFethab = ProIncGadoFethab &ProIncSojaFethab = ProIncSojaFethab endif
Exit when none &UserMessage = criaUserMessageError('Produto não encontrado!','') return endfor EndSub
Sub 'gravaItemNota' // Busca informações necessárias para calcular impostos do 'buscaConfiguracaoImposto'
// Busca preço unitário de venda RetornaTabelaFilial(&EmpCod, &FilCod, &FilTabCod) RetornaPrecoUnitarioVenda(&EmpCod, &FilTabCod, '', &NFeProCod, &NfeProGraCod, 1, &NfeDtaEms, &NfeDtaFat, &NfeProVlrUnt)
// Calcula valor total &NfeProVlrTot = &NfeProQtd * &NfeProVlrUnt
// Calcula bases de cálculo e impostos do 'calculaImpostosItem'
// Prepara SDTs para gravação // Grava o item // Usa a mesma função da tela, mas para modelo 55 pode ser diferente // Verificando se existe função específica para modelo 55 // Por enquanto, vamos usar a função genérica se disponível GravaNotaFiscalModelo65_ItemCBSIBS(&EmpCod, &FilCod, &NfeCod, &NfeItmCod, &NFeProCod, &NfeProGraCod, &NfeProNom, &NfeProQtd, &NfeProVlrUnt, &NfeProVlrTot, &NfeEmbUnd, &NfeEmbUndTrib, &ProOriTriCod, &NfeNcmCod, &NfeNcmCest, &NfeProDadAdi, &NfeProII_Bas, &NfeProII_DspAdu, &NfeProII_IOF, &NfeProII_vlr, &NfeProCodAnp, &NfeProDscAnp, &NfeProPerGlp, &NfeProPerGni, &NfeProPerGnn, &NfeProVlrPar, &NfeProRctPen, &NfeProBasIcmsRet, &NfeProTaxIcmsRet, &NfeProVlrIcmsRet, &NfeProBar, &NfeProBarTrib, &NfeNitemPed, &NfeProVlrDig, &sdtCadastroTabelaImpostoCbs, &sdtImpostoProduto)
// Grava informações adicionais se necessário do 'gravaInformacoesAdicionaisItem' EndSub
Sub 'buscaConfiguracaoImposto' // Busca regime tributário da filial For each order EmpCod, FilCod where EmpCod = &EmpCod where FilCod = &FilCod
if FilBasImp = 0 &FilBasImp = FilCod Else &FilBasImp = FilBasImp endif
&FilCidUfeCod = FilCidUfeCod
Exit endfor
RetornaRegimeTributarioFilial(&EmpCod, &FilBasImp, &FilRegTrib, &CImpOriUfeCod)
// Busca dados do cliente para destino For each order EmpCod, PesCod where EmpCod = &EmpCod where PesCod = &NFeCliCod
&PedCliCidUfeCod = PesEntUfeCod &PedCliGruImpCod = PesGruImpCod
Exit endfor
// Busca tipo de lançamento para base de imposto For each order EmpCod, LctCod where EmpCod = &EmpCod where LctCod = &NFeLctCod &LctBasImpCod = LctBasImpCod Exit endfor
// Prepara SDT para buscar configuração de impostos &sdtCadastroTabelaImpostoCbs = new() &sdtCadastroTabelaImpostoCbs.EmpCod = &EmpCod &sdtCadastroTabelaImpostoCbs.CImpTbFilCod = &FilBasImp &sdtCadastroTabelaImpostoCbs.CImpLctCod = &LctBasImpCod &sdtCadastroTabelaImpostoCbs.CImpOriUfeCod = &CImpOriUfeCod &sdtCadastroTabelaImpostoCbs.CImpDstUfeCod = &PedCliCidUfeCod &sdtCadastroTabelaImpostoCbs.CImpGruImpCod = &PedCliGruImpCod &sdtCadastroTabelaImpostoCbs.CImpCatCod = &ProCatCod &sdtCadastroTabelaImpostoCbs.ProCod = &NFeProCod &sdtCadastroTabelaImpostoCbs.CImpDtaIni = ServerDate()
prcRetornaConfiguracaoImposto_IBSCBS(&sdtCadastrotabelaImpostoCbs)
// Carrega configurações de impostos &Varchar = &sdtCadastrotabelaImpostoCbs.CImpCstCod.ToString() &NfeSitCod = &Varchar &NfeProCBenef = &sdtCadastrotabelaImpostoCbs.CImpCBenef &NfeCfoCod = &sdtCadastrotabelaImpostoCbs.CImpCfoCod &ImpAlqMVA = &sdtCadastrotabelaImpostoCbs.CImpAlqMVA &NfeProTaxIcms = &sdtCadastrotabelaImpostoCbs.CImpAlqIcmInt &NfeProTaxRedIcms = &sdtCadastrotabelaImpostoCbs.CImpRedAlqIcmInt &NfeProTaxIcmsSt = &sdtCadastrotabelaImpostoCbs.CImpAlqIcmExt &NfeProTaxRedIcmsSt = &sdtCadastrotabelaImpostoCbs.CImpRedAlqIcmExt &NfeProTaxCofins = &sdtCadastrotabelaImpostoCbs.CImpCofins &NfeCstCofins = &sdtCadastrotabelaImpostoCbs.nfeCstCofins &NfeProTaxPIS = &sdtCadastrotabelaImpostoCbs.CImpPis &NfeCstPIS = &sdtCadastrotabelaImpostoCbs.CImpCstPisCofins &NfeCstIpi = &sdtCadastrotabelaImpostoCbs.CImpCstIpi &NfeProCofinsRed = &sdtCadastrotabelaImpostoCbs.CImpCofinsRed &NfeProPisRed = &sdtCadastrotabelaImpostoCbs.CImpPisRed &NfeProTaxIpi = &sdtCadastrotabelaImpostoCbs.CImpIPI &NfeIpiEnq = &sdtCadastrotabelaImpostoCbs.CImpIpiEnq &NfeProTaxDif = &sdtCadastrotabelaImpostoCbs.CImpDif &NfeProUFDest = &sdtCadastrotabelaImpostoCbs.CImpALqIcmUFDest &ImpIcmsRet = &sdtCadastrotabelaImpostoCbs.CImpIcmsRet EndSub
Sub 'calculaImpostosItem' // Calcula ICMS Retenção &NfeProBasIcmsRet = &ProBasIcmsRet * &NfeProQtd &NfeProTaxIcmsRet = &ProTaxIcmsRet if &ProTaxIcmsRet > 0 and &NfeProBasIcmsRet > 0 and &ImpIcmsRet = 'S' &NfeProVlrIcmsRet = &NfeProBasIcmsRet - ((&NfeProBasIcmsRet * &ProTaxIcmsRet) / 100) Else &NfeProBasIcmsRet = 0 &NfeProVlrIcmsRet = 0 &NfeProTaxIcmsRet = 0 endif
// Calcula valor total &NfeProVlrTot = &NfeProQtd * &NfeProVlrUnt
// Calcula bases de cálculo // Para CST 02, 15, 53, 61 usa peso líquido if &sdtCadastrotabelaImpostoCbs.CImpCstCod in (domSituacaoTributariaVarchar.CST02, domSituacaoTributariaVarchar.CST15, domSituacaoTributariaVarchar.CST53, domSituacaoTributariaVarchar.cst61) &NfeProBasIcms = &NfeProQtd * &ProPesLiq &NfeProBasIcmsSt = &NfeProBasIcms &NfeProBasIpi = &NfeProBasIcms &NfeProBasPIS = &NfeProBasIcms &NfeProBasCOFINS = &NfeProBasIcms
&sdtImpostoProduto = new() &sdtImpostoProduto.ProBasVlrIcm = &NfeProBasIcms &sdtImpostoProduto.ProBasVlrIcmSt = &NfeProBasIcms &sdtImpostoProduto.ProBasVlrIpi = &NfeProBasIcms &sdtImpostoProduto.ProBasPis = &NfeProBasIcms &sdtImpostoProduto.ProBasCofins = &NfeProBasIcms &sdtImpostoProduto.ValorTotalProduto = &NfeProBasIcms Else &NfeProBasIcms = &NfeProVlrTot &NfeProBasIcmsSt = &NfeProVlrTot &NfeProBasIpi = &NfeProVlrTot &NfeProBasPIS = &NfeProVlrTot &NfeProBasCOFINS = &NfeProVlrTot
&sdtImpostoProduto = new() &sdtImpostoProduto.ProBasVlrIcm = &NfeProBasIcms &sdtImpostoProduto.ProBasVlrIcmSt = &NfeProBasIcmsSt &sdtImpostoProduto.ProBasVlrIpi = &NfeProBasIpi &sdtImpostoProduto.ProBasPis = &NfeProBasPIS &sdtImpostoProduto.ProBasCofins = &NfeProBasCOFINS &sdtImpostoProduto.ValorTotalProduto = &NfeProVlrTot endif
// Calcula impostos usando a função específica &NfeProVlrDig = Status_SimNao.Nao CalculaImposto_IBSCBS(&sdtCadastrotabelaImpostoCbs, &sdtImpostoProduto)
// Atualiza valores calculados &NfeProBasIpi = &sdtImpostoProduto.ProBasVlrIpi &NfeProBasIcms = &sdtImpostoProduto.ProBasVlrIcm &NfeProBasIcmsSt = &sdtImpostoProduto.ProBasVlrIcmSt &NfeProVlrIpi = &sdtImpostoProduto.ProVlrIpi &NfeProVlrIcms = &sdtImpostoProduto.ProVlrIcm &NfeProVlrImcsSt = &sdtImpostoProduto.ProVlrIcmSt &NfeProBasPIS = &sdtImpostoProduto.ProBasPis &NfeProBasCofins = &sdtImpostoProduto.ProBasCofins &NfeProVlrPis = &sdtImpostoProduto.ProVlrPis &NfeProVlrCofins = &sdtImpostoProduto.ProVlrCofins &NfeProVlrDif = &sdtImpostoProduto.ProVlrDif
// Valores de importação &NfeProII_Bas = 0 &NfeProII_DspAdu = 0 &NfeProII_IOF = 0 &NfeProII_vlr = 0 EndSub
Sub 'gravaInformacoesAdicionaisItem' // Grava rastreabilidade (se houver) &sdtProdutoLote = new() GravaNotaFiscalRastreio(&EmpCod, &FilCod, &NfeCod, &NfeItmCod, &NfeProMedAnv, &NfeProMedMot, &NfeProMedVlrMax, &sdtProdutoLote)
// Grava informações do produtor (se aplicável) if &FilCidUfeCod = 'MT' GravaNotaFiscalProdutor(&EmpCod, &FilCod, &NfeCod, &NfeItmCod, &NfeProVlrFabov, &NfeProVlrFethabGado, &NfeProVlrIagro, &NfeProVlrFethabSoja, &NfeProVlrInc) endif EndSub
